// nodes/apiNode.js
import { useState } from 'react';
import { BaseNode, fieldStyle } from './BaseNode';
import { useStore } from '../store';

export const ApiNode = ({ id, data }) => {
  const updateNodeField = useStore((s) => s.updateNodeField);
  const [url, setUrl] = useState(data?.url ?? 'https://api.example.com/endpoint');
  const [method, setMethod] = useState(data?.method ?? 'GET');

  return (
    <BaseNode
      id={id}
      title="API Call"
      icon="🌐"
      accentColor="#38bdf8"
      inputs={[{ id: 'body', label: 'body' }, { id: 'headers', label: 'headers' }]}
      outputs={[{ id: 'response', label: 'response' }, { id: 'status', label: 'status' }]}
      minWidth={260}
    >
      <div style={fieldStyle.group}>
        <label style={fieldStyle.label}>Method</label>
        <select
          style={fieldStyle.select}
          value={method}
          onChange={(e) => {
            setMethod(e.target.value);
            updateNodeField(id, 'method', e.target.value);
          }}
        >
          <option>GET</option>
          <option>POST</option>
          <option>PUT</option>
          <option>DELETE</option>
          <option>PATCH</option>
        </select>
      </div>
      <div style={fieldStyle.group}>
        <label style={fieldStyle.label}>URL</label>
        <input
          style={fieldStyle.input}
          value={url}
          onChange={(e) => {
            setUrl(e.target.value);
            updateNodeField(id, 'url', e.target.value);
          }}
        />
      </div>
    </BaseNode>
  );
};
